import { Text as PDFText, View } from '@react-pdf/renderer';
import type { Style } from '@react-pdf/types';
import type React from 'react';
import { usePdfxTheme, useSafeMemo } from '../lib/pdfx-theme-context';
import { createListStyles } from './pdfx-list.styles';
import type { ListItem, ListVariant, PdfListProps } from './pdfx-list.types';

type Styles = ReturnType<typeof createListStyles>;
type GapProp = 'xs' | 'sm' | 'md';

function getGapStyle(gap: GapProp, styles: Styles): Style {
  if (gap === 'xs') return styles.itemRowGapXs;
  if (gap === 'md') return styles.itemRowGapMd;
  return styles.itemRowGapSm;
}

function buildRowStyles(
  index: number,
  total: number,
  gap: GapProp,
  styles: Styles,
  align: 'start' | 'center' = 'start'
): Style[] {
  const row: Style[] = [align === 'center' ? styles.itemRowCenter : styles.itemRow];
  if (index !== total - 1) row.push(getGapStyle(gap, styles));
  return row;
}

/** Bullet dot marker — solid filled for level 0, outline ring for nested levels. */
function dotMarker(level: number, styles: Styles): React.ReactElement {
  return level === 0 ? (
    <View style={styles.markerBulletWrap}>
      <View style={styles.markerBulletDot} />
    </View>
  ) : (
    <View style={styles.markerBulletSubWrap}>
      <View style={styles.markerBulletSubDot} />
    </View>
  );
}

function renderBulletItem(
  item: ListItem,
  index: number,
  total: number,
  gap: GapProp,
  styles: Styles,
  level: number
): React.ReactElement {
  return (
    <View key={index}>
      <View style={buildRowStyles(index, total, gap, styles)}>
        {dotMarker(level, styles)}
        {/* flex:1 on the View, NOT on the Text — avoids Yoga height underestimation
            for multi-line Text nodes that would cause overlapping rows. */}
        <View style={styles.itemTextWrap}>
          <PDFText style={styles.itemText}>{item.text}</PDFText>
        </View>
      </View>
      {item.children && item.children.length > 0
        ? renderItemList(item.children, 'bullet', gap, styles, level + 1)
        : null}
    </View>
  );
}

function renderNumberedItem(
  item: ListItem,
  index: number,
  total: number,
  gap: GapProp,
  styles: Styles
): React.ReactElement {
  return (
    <View key={index} style={buildRowStyles(index, total, gap, styles, 'center')}>
      <View style={styles.markerNumberBadge}>
        <PDFText style={styles.markerNumberText}>{`${index + 1}`}</PDFText>
      </View>
      <View style={styles.itemTextWrap}>
        <PDFText style={styles.itemText}>{item.text}</PDFText>
      </View>
    </View>
  );
}

function renderChecklistItem(
  item: ListItem,
  index: number,
  total: number,
  gap: GapProp,
  styles: Styles
): React.ReactElement {
  const isChecked = item.checked ?? true;
  return (
    <View key={index} style={buildRowStyles(index, total, gap, styles, 'center')}>
      <View style={[styles.checkBox, isChecked ? styles.checkBoxChecked : {}]}>
        {isChecked ? <PDFText style={styles.checkMark}>✓</PDFText> : null}
      </View>
      <View style={styles.itemTextWrap}>
        <PDFText style={styles.itemText}>{item.text}</PDFText>
      </View>
    </View>
  );
}

function renderIconItem(
  item: ListItem,
  index: number,
  total: number,
  gap: GapProp,
  styles: Styles
): React.ReactElement {
  return (
    <View key={index} style={buildRowStyles(index, total, gap, styles, 'center')}>
      <View style={styles.iconBox}>
        <PDFText style={styles.iconMark}>★</PDFText>
      </View>
      <View style={styles.itemTextWrap}>
        <PDFText style={styles.itemText}>{item.text}</PDFText>
      </View>
    </View>
  );
}

function renderMultiLevelItem(
  item: ListItem,
  index: number,
  total: number,
  gap: GapProp,
  styles: Styles,
  level: number
): React.ReactElement {
  return (
    <View key={index}>
      <View style={buildRowStyles(index, total, gap, styles)}>
        {dotMarker(level, styles)}
        <View style={styles.itemTextWrap}>
          <PDFText
            style={[
              level === 0 ? styles.itemText : styles.itemTextSub,
              level === 0 ? styles.itemTextBold : {},
            ]}
          >
            {item.text}
          </PDFText>
        </View>
      </View>
      {item.children && item.children.length > 0
        ? renderItemList(item.children, 'multi-level', gap, styles, level + 1)
        : null}
    </View>
  );
}

function renderDescriptiveItem(
  item: ListItem,
  index: number,
  total: number,
  gap: GapProp,
  styles: Styles
): React.ReactElement {
  return (
    <View key={index} style={buildRowStyles(index, total, gap, styles)}>
      <View style={styles.descriptiveAccent} />
      <View style={styles.descriptiveContent}>
        <PDFText style={styles.descriptiveTitle}>{item.text}</PDFText>
        {item.description ? (
          <PDFText style={styles.descriptiveDesc}>{item.description}</PDFText>
        ) : null}
      </View>
    </View>
  );
}

function renderItem(
  item: ListItem,
  index: number,
  total: number,
  variant: ListVariant,
  gap: GapProp,
  styles: Styles,
  level: number
): React.ReactElement | null {
  switch (variant) {
    case 'bullet':
      return renderBulletItem(item, index, total, gap, styles, level);
    case 'numbered':
      return renderNumberedItem(item, index, total, gap, styles);
    case 'checklist':
      return renderChecklistItem(item, index, total, gap, styles);
    case 'icon':
      return renderIconItem(item, index, total, gap, styles);
    case 'multi-level':
      return renderMultiLevelItem(item, index, total, gap, styles, level);
    case 'descriptive':
      return renderDescriptiveItem(item, index, total, gap, styles);
  }
}

function renderItemList(
  items: ListItem[],
  variant: ListVariant,
  gap: GapProp,
  styles: Styles,
  level: number
): React.ReactElement {
  return (
    <View style={level > 0 ? styles.childrenContainer : undefined}>
      {items.map((item, index) =>
        renderItem(item, index, items.length, variant, gap, styles, level)
      )}
    </View>
  );
}

export function PdfList({
  items,
  variant = 'bullet',
  gap = 'sm',
  style,
  noWrap = false,
  _level = 0,
}: PdfListProps) {
  const theme = usePdfxTheme();
  const styles = useSafeMemo(() => createListStyles(theme), [theme]);

  const containerStyles: Style[] = [styles.container];
  if (_level > 0) containerStyles.push(styles.childrenContainer);
  const styleArray = style ? [...containerStyles, style] : containerStyles;

  return (
    <View wrap={!noWrap} style={styleArray}>
      {items.map((item, index) =>
        renderItem(item, index, items.length, variant, gap, styles, _level)
      )}
    </View>
  );
}

import { StyleSheet } from '@react-pdf/renderer';
import { usePdfxTheme } from '../lib/pdfx-theme-context';
type PdfxTheme = ReturnType<typeof usePdfxTheme>;

/**
 * Creates all list styles derived from the active theme.
 * @param t - The resolved PdfxTheme instance.
 */
export function createListStyles(t: PdfxTheme) {
  const { borderRadius, spacing, fontWeights, typography } = t.primitives;

  return StyleSheet.create({
    container: {
      display: 'flex',
      flexDirection: 'column',
      width: '100%',
      marginBottom: t.spacing.componentGap,
    },
    itemRow: {
      flexDirection: 'row',
      alignItems: 'flex-start',
    },
    itemRowCenter: {
      flexDirection: 'row',
      alignItems: 'center',
    },
    itemRowGapXs: { marginBottom: spacing[1] },
    itemRowGapSm: { marginBottom: spacing[2] },
    itemRowGapMd: { marginBottom: spacing[3] },
    markerBulletWrap: {
      width: spacing[4],
      alignItems: 'center',
      justifyContent: 'flex-start',
      marginTop: spacing[1],
    },
    markerBulletDot: {
      width: 5,
      height: 5,
      borderRadius: 3,
      backgroundColor: t.colors.primary,
    },
    markerBulletSubWrap: {
      width: spacing[4],
      alignItems: 'center',
      justifyContent: 'flex-start',
      marginTop: spacing[1],
    },
    markerBulletSubDot: {
      width: 4,
      height: 4,
      borderRadius: 2,
      borderWidth: 1,
      borderStyle: 'solid',
      borderColor: t.colors.mutedForeground,
      backgroundColor: 'transparent',
    },
    markerNumberBadge: {
      width: spacing[5],
      height: spacing[5],
      borderRadius: spacing[5],
      backgroundColor: t.colors.primary,
      alignItems: 'center',
      justifyContent: 'center',
      marginRight: spacing[2],
    },
    markerNumberText: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: typography.xs,
      color: t.colors.primaryForeground,
      fontWeight: fontWeights.bold,
    },
    checkBox: {
      width: spacing[4],
      height: spacing[4],
      borderWidth: 1.5,
      borderColor: t.colors.border,
      borderStyle: 'solid',
      borderRadius: 3,
      marginRight: spacing[2],
      alignItems: 'center',
      justifyContent: 'center',
      backgroundColor: t.colors.background,
    },
    checkBoxChecked: {
      backgroundColor: t.colors.success,
      borderColor: t.colors.success,
    },
    checkMark: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: 8,
      color: t.colors.background,
      fontWeight: fontWeights.bold,
    },
    iconBox: {
      width: spacing[5],
      height: spacing[5],
      borderRadius: borderRadius.md,
      backgroundColor: t.colors.primary,
      alignItems: 'center',
      justifyContent: 'center',
      marginRight: spacing[2],
    },
    iconMark: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: 9,
      color: t.colors.primaryForeground,
      fontWeight: fontWeights.bold,
    },
    itemText: {
      // No flex here — Text nodes with flex shorthand get flexBasis:0, which causes
      // Yoga to under-measure multi-line text height → overlapping rows.
      // flex:1 must live on the wrapping View, not on the Text itself.
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize,
      lineHeight: t.typography.body.lineHeight,
      color: t.colors.foreground,
    },
    itemTextSub: {
      // Same: no flex — see itemText comment.
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize - 0.5,
      lineHeight: t.typography.body.lineHeight,
      color: t.colors.mutedForeground,
    },
    itemTextWrap: {
      // Companion to itemText / itemTextSub. Apply this to the View that wraps
      // the Text so flex expansion happens at the View level, not the Text level.
      flex: 1,
    },
    itemTextBold: {
      fontWeight: fontWeights.semibold,
    },
    descriptiveTitle: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize,
      lineHeight: t.typography.body.lineHeight,
      color: t.colors.foreground,
      fontWeight: fontWeights.semibold,
    },
    descriptiveDesc: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: typography.sm,
      lineHeight: t.typography.body.lineHeight,
      color: t.colors.mutedForeground,
      marginTop: 1,
    },
    descriptiveAccent: {
      width: 3,
      borderRadius: borderRadius.sm,
      backgroundColor: t.colors.primary,
      marginRight: spacing[3],
      minHeight: spacing[4],
    },
    descriptiveContent: {
      flex: 1,
    },
    childrenContainer: {
      marginLeft: spacing[5],
      marginTop: spacing[1],
      display: 'flex',
      flexDirection: 'column',
    },
  });
}

import type { Style } from '@react-pdf/types';

/** List visual style variant. */
export type ListVariant =
  | 'bullet'
  | 'numbered'
  | 'checklist'
  | 'icon'
  | 'multi-level'
  | 'descriptive';

/**
 * A single list item, optionally with nested children.
 * Props - `text` | `description` | `checked` | `children`
 * @see {@link ListItem}
 */
export interface ListItem {
  text: string;
  description?: string;
  checked?: boolean;
  children?: ListItem[];
}

/**
 * List of items with multiple style variants including bullet, numbered, checklist, and descriptive.
 * Props - `items` | `variant` | `gap` | `style` | `_level` | `noWrap`
 * @see {@link PdfListProps}
 */
export interface PdfListProps {
  items: ListItem[];
  /**
   * @default 'bullet'
   */
  variant?: ListVariant;
  /**
   * @default 'sm'
   */
  gap?: 'xs' | 'sm' | 'md';
  style?: Style;
  _level?: number;
  /**
   * @default false
   */
  noWrap?: boolean;
}
